package main

import (
    "fmt"
    "testing"
)

// ---- Code to benchmark ----
func Factorial(n int) int {
    if n <= 1 {
        return 1
    }
    return n * Factorial(n-1)
}

func FactorialIterative(n int) int {
    result := 1
    for i := 2; i <= n; i++ {
        result *= i
    }
    return result
}

// ---- Benchmark functions ----
// Benchmarks must start with 'Benchmark' and take *testing.B
func BenchmarkFactorial(b *testing.B) {
    for i := 0; i < b.N; i++ {
        Factorial(10)
    }
}

func BenchmarkFactorialIterative(b *testing.B) {
    for i := 0; i < b.N; i++ {
        FactorialIterative(10)
    }
}

func BenchmarkFactorialWithSize(b *testing.B) {
    sizes := []int{5, 10, 15, 20}
    for _, size := range sizes {
        b.Run(fmt.Sprintf("size=%d", size), func(b *testing.B) {
            for i := 0; i < b.N; i++ {
                Factorial(size)
            }
        })
    }
}

// ---- Run benchmarks ----
// go test -bench=.
// go test -bench=Factorial
// go test -bench=BenchmarkFactorial -benchmem
// go test -bench=BenchmarkFactorial -benchtime=10s

