package main

import (
    "strings"
    "testing"
)

func StringLength(s string) int {
    return len(s)
}

func BenchmarkStringLength(b *testing.B) {
    sizes := []struct {
        name  string
        input string
    }{
        {"short", "hello"},
        {"medium", strings.Repeat("a", 50)},
        {"long", strings.Repeat("a", 500)},
    }

    for _, size := range sizes {
        b.Run(size.name, func(b *testing.B) {
            for i := 0; i < b.N; i++ {
                StringLength(size.input)
            }
        })
    }
}
